const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');

function sanitize(text) {
  return String(text || '')
    .replace(/postgres(ql)?:\/\/[^\s]+/gi, '[REDACTED_DB_URL]')
    .replace(/[A-Za-z0-9_-]{20,}\.[A-Za-z0-9_-]{6,}\.[A-Za-z0-9_-]{20,}/g, '[REDACTED_TOKEN]')
    .replace(/(?:key|token|secret|password|apikey)[\s]*[=:]\s*\S+/gi, '[REDACTED_CREDENTIAL]')
    .replace(/sk-[a-zA-Z0-9]{20,}/g, '[REDACTED_API_KEY]');
}

function safeId(value, fallback = 'unknown') {
  const v = value === undefined || value === null || value === '' ? fallback : value;
  return String(v);
}

const execution = item.execution || {};
const trigger = item.trigger || {};
const workflow = item.workflow || {};
const triggerError = trigger.error || {};
const executionError = execution.error || {};

const executionId = safeId(execution.id || item.executionId || 'unknown');
const workflowName = safeId(workflow.name || item.workflowName || 'unknown');
const workflowId = safeId(workflow.id || item.workflowId || 'unknown');

const rawError =
  executionError.message ||
  executionError.cause?.message ||
  triggerError.message ||
  triggerError.cause?.message ||
  item.errorMessage ||
  'No error message available';

const failedNode = safeId(
  execution.lastNodeExecuted ||
  executionError.node?.name ||
  triggerError.node?.name ||
  item.failedNode ||
  'trigger_or_unknown'
);

const baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';
const executionUrl = execution.url || (executionId !== 'unknown' ? `${baseUrl}/executions/${executionId}` : `${baseUrl}/executions`);
const retryOf = execution.retryOf || item.retryOf || null;
const executionMode = execution.mode || trigger.mode || item.mode || 'unknown';

const msg = String(rawError || '').toLowerCase();

const category = /credentials|credential|auth|unauthorized|forbidden|401|403/.test(msg)
  ? 'auth'
  : /rate.?limit|429|quota/.test(msg)
    ? 'rate_limit'
    : /timeout|etimedout|504/.test(msg)
      ? 'timeout'
      : /econnrefused|enotfound|econnreset|network|502|503/.test(msg)
        ? 'connectivity'
        : /cannot read prop|undefined|null|typeerror|referenceerror|syntaxerror/.test(msg)
          ? 'code_bug'
          : /memory|heap|out of memory/.test(msg)
            ? 'resource'
            : 'unknown';

const severity = category === 'auth'
  ? 'critical'
  : ['rate_limit', 'timeout', 'connectivity', 'resource'].includes(category)
    ? 'warning'
    : 'error';

const severityIcon = severity === 'critical' ? '🔴' : severity === 'warning' ? '🟡' : '🟠';
const errorMessage = sanitize(rawError).substring(0, 1000);
const retryable = ['connectivity', 'rate_limit', 'timeout'].includes(category) && !retryOf && !(/credentials|credential|auth|unauthorized|forbidden|401|403/i.test(rawError));

const now = Date.now();
const traceId = `err-${executionId}-${now}`;
const fingerprint = `${workflowName}::${failedNode}::${errorMessage.substring(0, 100)}`
  .toLowerCase()
  .replace(/[^a-z0-9:]/g, '_')
  .substring(0, 250);

const debounceKey = 'debounce_' + fingerprint;
const burstKey = 'burst_' + fingerprint;
const lastSeen = staticData[debounceKey] || 0;
const isDebounced = (now - lastSeen) < 30000;

let burstSuppressedCount = staticData[burstKey] || 0;

if (isDebounced) {
  burstSuppressedCount += 1;
  staticData[burstKey] = burstSuppressedCount;
} else {
  staticData[debounceKey] = now;
  staticData[burstKey] = 0;
}

for (const k of Object.keys(staticData)) {
  if (k.startsWith('debounce_') && (now - staticData[k]) > 300000) delete staticData[k];
  if (k.startsWith('burst_') && staticData[k] === 0) delete staticData[k];
}

return [{
  json: {
    executionId,
    workflowName,
    workflowId,
    errorMessage,
    rawError: sanitize(rawError).substring(0, 1000),
    failedNode,
    executionUrl,
    severity,
    severityIcon,
    category,
    retryable,
    retryOf,
    executionMode,
    traceId,
    fingerprint,
    isDebounced,
    burstSuppressedCount,
    workflow_version: 'v1_lean'
  }
}];

const item = $input.first().json;
const MONITORING_WORKFLOW_IDS = [
  $env.SUPERVISOR_WORKFLOW_ID || '',
  $env.HEARTBEAT_WORKFLOW_ID || '',
  $env.RETENTION_WORKFLOW_ID || ''
].filter(Boolean).map(String);

const monitoringNames = ['Supervisor Core', 'Heartbeat Monitor', 'Data Retention'];

const isSelfLoop = MONITORING_WORKFLOW_IDS.includes(String(item.workflowId)) ||
  monitoringNames.some(n => String(item.workflowName || '').toLowerCase().includes(n.toLowerCase()));

return [{ json: { ...item, isSelfLoop } }];

