const circuitData = $input.first().json || {};
const errorData = $('Self-Loop Check').first().json;

const isDbError = !!(circuitData.error && typeof circuitData.error === 'object' && circuitData.error.message) || !circuitData.status;
const status = isDbError ? 'unknown' : String(circuitData.status || 'unknown');
const previousStatus = isDbError ? 'unknown' : String(circuitData.previous_status || status);
const errorCount = isDbError ? 0 : (parseInt(circuitData.error_count, 10) || 0);
const isTransition = !isDbError && !!circuitData.previous_status && status !== previousStatus;
const isCircuitOpen = status === 'open';
const isNewlyOpen = isTransition && status === 'open';
const isCircuitSuppressing = isCircuitOpen && !isNewlyOpen;

return [{
  json: {
    ...errorData,
    circuit_status: status,
    previous_status: previousStatus,
    error_count: errorCount,
    is_transition: isTransition,
    transition_logged: !!circuitData.transition_logged,
    is_circuit_open: isCircuitOpen,
    is_newly_open: isNewlyOpen,
    is_circuit_suppressing: isCircuitSuppressing,
    is_db_error: isDbError,
    db_error_message: circuitData.error?.message || ''
  }
}];

const item = $input.first().json;
const circuitLine = item.is_db_error
  ? 'Circuit: ⚠️ unknown — Postgres unavailable'
  : `Circuit: Error ${item.error_count} of 5`;

const categoryLabel = String(item.category || 'unknown').replace(/_/g, ' ');
const burstLine = item.burstSuppressedCount > 0
  ? `\n⚡ Suppressed duplicates since previous alert: ${item.burstSuppressedCount}`
  : '';

const retryLine = item.retryable
  ? 'Retryable: yes — auto-retry eligible'
  : item.retryOf
    ? 'Retryable: no — this execution is already a retry'
    : 'Retryable: no';

const text = `${item.severityIcon} <b>${item.severity.toUpperCase()} — WORKFLOW ERROR</b>\n\n<b>Workflow:</b> ${item.workflowName}\n<b>Failed Node:</b> ${item.failedNode}\n<b>Category:</b> ${categoryLabel}\n<b>Error:</b> <code>${item.errorMessage.substring(0, 500)}</code>\n<b>Execution:</b> ${item.executionUrl}\n<b>${retryLine}</b>\n<b>${circuitLine}</b>${burstLine}\n\n<b>Trace:</b> <code>${item.traceId}</code>\n<b>Timestamp:</b> ${new Date().toISOString()}`;

return [{ json: { ...item, alertText: text } }];

const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');

const now = Date.now();
const retryKey = 'retry_' + item.fingerprint;
const retryMetaKey = retryKey + '_meta';
const retryMeta = staticData[retryMetaKey] || { count: 0, firstSeen: now };

if ((now - retryMeta.firstSeen) > 3600000) {
  retryMeta.count = 0;
  retryMeta.firstSeen = now;
}

const allowedCategory = ['connectivity', 'rate_limit', 'timeout'].includes(item.category);
const isRetryExecution = !!item.retryOf;
const belowLimit = retryMeta.count < 2;
const hasExecutionId = item.executionId && item.executionId !== 'unknown';

const shouldRetry = !!item.retryable && allowedCategory && !isRetryExecution && belowLimit && hasExecutionId;

if (shouldRetry) {
  retryMeta.count += 1;
  retryMeta.lastRetryAt = now;
  staticData[retryMetaKey] = retryMeta;
}

for (const k of Object.keys(staticData)) {
  if (k.startsWith('retry_') && k.endsWith('_meta')) {
    const meta = staticData[k];
    if (meta && meta.firstSeen && (now - meta.firstSeen) > 3600000) delete staticData[k];
  }
}

const baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';
const retryApiUrl = `${baseUrl}/api/v1/executions/${item.executionId}/retry`;

return [{
  json: {
    ...item,
    shouldRetry,
    retryAttempt: retryMeta.count,
    retryLimit: 2,
    retryApiUrl,
    autoRetryReason: shouldRetry
      ? 'retryable transient failure'
      : isRetryExecution
        ? 'execution is already a retry'
        : !allowedCategory
          ? 'category not auto-retryable'
          : !belowLimit
            ? 'retry limit reached for fingerprint'
            : !hasExecutionId
              ? 'missing execution id'
              : 'not retryable'
  }
}];

const staticData = $getWorkflowStaticData('global');
const item = $input.first().json || {};
if (!staticData.eventFailures) staticData.eventFailures = [];
staticData.eventFailures.push({
  timestamp: new Date().toISOString(),
  traceId: item.traceId || 'unknown',
  eventType: item.eventType || 'alert_failed',
  source: 'Supervisor Core',
  workflowName: item.workflowName || 'unknown',
  failedNode: item.failedNode || 'unknown',
  reason: item.error?.message || item.db_error_message || 'Postgres, Telegram, or auto-retry delivery failed — cached for heartbeat pickup'
});
if (staticData.eventFailures.length > 50) {
  staticData.droppedCacheCount = (staticData.droppedCacheCount || 0) + (staticData.eventFailures.length - 50);
  staticData.eventFailures = staticData.eventFailures.slice(-50);
}
return [{ json: { cached: true, count: staticData.eventFailures.length, droppedCacheCount: staticData.droppedCacheCount || 0 } }];
